using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(openAiKey))
{
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    return 1;
}

// --- Set up the chat client with tools ---
IChatClient innerClient = new OpenAIClient(openAiKey).GetChatClient(model).AsIChatClient();

var notes = new NoteStore();

IChatClient agent = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(
        (string note) => notes.Add(note),
        "save_note",
        "Saves a note to the research notebook. Use this to record key findings."),
    AIFunctionFactory.Create(
        () => notes.GetAll(),
        "read_notes",
        "Reads all saved research notes.")
};

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

Console.WriteLine($"\nResearching: {topic}\n{"".PadRight(40, '-')}");

// --- Run the agent loop ---
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to research the given topic thoroughly.

        Strategy:
        1. Search the web for relevant information (perform 2-3 searches with different queries).
        2. Save important findings as notes using the save_note tool.
        3. After gathering enough information, read your notes and produce a final summary.

        Always save key facts before summarizing. Your final message should be a well-structured
        summary of your research findings.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}")
};

var options = new ChatOptions { Tools = tools };

var response = await agent.GetResponseAsync(messages, options);

Console.WriteLine($"\n{"".PadRight(40, '=')}\nRESEARCH SUMMARY\n{"".PadRight(40, '=')}\n");
Console.WriteLine(response.Text);

Console.WriteLine($"\n{"".PadRight(40, '-')}\nNotes collected: {notes.Count}");
return 0;

// --- Tool Implementations ---

[Description("Searches the web for the given query and returns relevant results. Use this to find information about any topic.")]
static async Task<string> SearchWeb([Description("The search query string")] string query)
{
    Console.WriteLine($"  🔍 Searching: \"{query}\"");
    try
    {
        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
        // Use DuckDuckGo instant answer API as a free search endpoint
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1&skip_disambig=1";
        var json = await http.GetStringAsync(url);
        // Return raw JSON — the LLM can parse it
        if (json.Length > 4000)
            json = json[..4000];
        return string.IsNullOrWhiteSpace(json) ? "No results found." : json;
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

// --- Note Store ---
class NoteStore
{
    private readonly List<string> _notes = [];
    public int Count => _notes.Count;
    public string Add(string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }
    public string GetAll() =>
        _notes.Count == 0
            ? "No notes saved yet."
            : string.Join("\n---\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
}

